import{V as n}from"./chunks/theme.C3DGj2Ge.js";import{c as a,o,j as t,a2 as r,a as i,G as s,k as l}from"./chunks/framework.DDIT__tB.js";const c={class:"tip custom-block"},p=JSON.parse('{"title":"📊 Diagram: CoCarNextGen","description":"","frontmatter":{},"headers":[],"relativePath":"examples/models/pcm/co-car.md","filePath":"examples/models/pcm/co-car.md"}'),d={name:"examples/models/pcm/co-car.md"},f=Object.assign(d,{setup(h){return(g,e)=>(o(),a("div",null,[e[2]||(e[2]=t("h1",{id:"📊-diagram-cocarnextgen",tabindex:"-1"},[i("📊 Diagram: CoCarNextGen "),t("a",{class:"header-anchor",href:"#📊-diagram-cocarnextgen","aria-label":'Permalink to "📊 Diagram: CoCarNextGen"'},"​")],-1)),t("div",c,[e[0]||(e[0]=t("p",{class:"custom-block-title"},"Available Online",-1)),e[1]||(e[1]=t("p",null,"This model (converted to a data flow diagram) is available to view using the online editor!",-1)),s(l(n),{text:"Open In Online Editor",href:"https://editor.dataflowanalysis.org/?file=https://raw.githubusercontent.com/DataFlowAnalysis/DataFlowAnalysis/refs/heads/main/bundles/org.dataflowanalysis.examplemodels/scenarios/pcm/CoCarNextGen/cocar.json&layout=true"})]),e[3]||(e[3]=r('<h2 id="🔗-link-to-original-paper-article" tabindex="-1">🔗 Link to Original Paper/Article <a class="header-anchor" href="#🔗-link-to-original-paper-article" aria-label="Permalink to &quot;🔗 Link to Original Paper/Article&quot;">​</a></h2><p><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/pcm/CoCarNextGen" target="_blank" rel="noreferrer">View Model Files in Repository</a></p><p><a href="https://www.audi-mediacenter.com/de/der-audi-a6-bis-2025-das-multitalent-in-der-business-class-10240/die-fakten-10242" target="_blank" rel="noreferrer">View Audi Fakten Source</a></p><p><a href="https://www.audi-mediacenter.com/de/der-neue-audi-a6-das-multitalent-in-der-business-class-10240/digitalisierung-10243" target="_blank" rel="noreferrer">View Audi Vernetzung Source</a></p><p><a href="https://www.audi-mediacenter.com/de/audi-technik-lexikon-7180/bedienung-und-anzeige-infotainment-16948" target="_blank" rel="noreferrer">View Audi Bedienung und Anzeige, Infotainment</a></p><p><a href="https://github.com/DataFlowAnalysis/DataFlowAnalysis/tree/main/bundles/org.dataflowanalysis.examplemodels/scenarios/pcm/CoCarNextGen" target="_blank" rel="noreferrer">Open Example Model in Example Models Bundles</a></p><h2 id="📝-short-description" tabindex="-1">📝 Short Description <a class="header-anchor" href="#📝-short-description" aria-label="Permalink to &quot;📝 Short Description&quot;">​</a></h2><p>This model represents a high-level architecture of an <strong>Audi A6 vehicle</strong>, focusing on sensor-based perception, centralized driver assistance, infotainment, and cloud connectivity. Environmental data is collected by multiple sensors (radar, cameras, ultrasonic) and fused centrally by the <strong>zFAS</strong> unit to create a consistent world model for driver assistance functions. These functions are processed by the <strong>Central Comfort Control Unit</strong> and translated into vehicle actuation commands via the <strong>DriveByWire Control Unit</strong>. In parallel, the <strong>MIB 2+</strong> infotainment platform provides human–machine interaction, navigation, voice control, smartphone integration, and <strong>Car-to-X</strong> communication. Connectivity to external cloud services, including <strong>HERE</strong> servers, <strong>Google</strong> navigation services, <strong>Audi Car-to-X</strong> backends, and online speech recognition, is realized through a <strong>Gateway Control Unit</strong>, enabling advanced navigation, traffic awareness, and connected services while maintaining a clear separation between in-vehicle systems and external backends.</p><h2 id="🔤-abbreviations" tabindex="-1">🔤 Abbreviations <a class="header-anchor" href="#🔤-abbreviations" aria-label="Permalink to &quot;🔤 Abbreviations&quot;">​</a></h2><ul><li>Car2X: Exchange of information between a vehicle and external entities, for example cloud backends.</li><li>HERE: HERE Technologies is a company that many car manufacturers use for maps, navigations, and traffic intelligence</li><li>zFAS: zentrales Fahrerassistenzsteuergerät</li></ul><h2 id="📖-extensive-description-if-possible" tabindex="-1">📖 Extensive Description (if possible) <a class="header-anchor" href="#📖-extensive-description-if-possible" aria-label="Permalink to &quot;📖 Extensive Description (if possible)&quot;">​</a></h2><p>For more information or more technical knowledge, please refer to the links above, as they were the basis of knowledge for the construction of this model.</p><p><strong>1. Sensor &amp; Perception Domain</strong> The Sensors block represents the full set of environment-sensing devices described for the Audi A6, which includes <strong>Radar sensors</strong> (long- and mid-range), front and surround-view <strong>cameras</strong> and <strong>ultrasonic sensors</strong>. These sensors provide raw environment data such as object distance and velocity, lane markings or obstacles.</p><p><strong>2. zFAS - Central Driver Assistance Processing</strong> The zFAS component is the central driver assistance control unit used by Audi. The previously mentioned sensor data is transmitted a FlexRay bus to the <strong>sensor fusion layer</strong>. Thi fusion produces a consistent world model, which is required for higher-level assistance functions.</p><p><strong>3.Central Comfort Control Unit</strong> This component hosts logical driver assistance functions, which rely on <strong>zFas</strong> outputs, which in turn are transmitted through the <strong>CAN bus</strong> which act as the central backbone between the <strong>zFAS, Infotainment systems, Vehicle CUs, Gateways CUs</strong>. The driver assistance functions represented in the model are the <strong>adaptive drive assist</strong>, <strong>efficiency assistant</strong> and the <strong>junction assistant</strong>.</p><p><strong>4. DriveByWire Control Unit</strong> The <strong>DriveByWireCU</strong> represents the interface to vehicle actuation (steering, acceleration, braking) and it receives control commands from the assistance functions.</p><p><strong>5. MIB 2+ (Modular Infotainment Baukasten)</strong> The <strong>MIB 2+</strong> unit is Audi´s infotainment platform and central HMI controller. The basic component is the <strong>MMITouchResponseDisplay</strong> which in turn connects with the different internal components:</p><ul><li><strong>1. MMI Search</strong>: This component allows the driver to do a normal <strong>Google</strong> search (for restaurants or the price of gas nearby) or a <strong>HERE location-based</strong> search.</li><li><strong>2. Voice Control</strong>: This component allows natural language interaction for online commands through the <strong>OnlineSpeechRecognitionBackend</strong>.</li><li><strong>3. Self-learning Navigation System</strong>: This component suggests routes based on the learned driver behavior and habits. The route and traffic calculations are done by the <strong>HERE servers</strong>. There is also the possibility to use the Google Earth navigation system, which is offered through the <strong>MMINavigationPlus</strong> component. This component connects to the Google Earth Navigation backend for achieving this purpose.</li><li><strong>4. Car2xModule</strong>: This component handles vehicle-to-backend communication for things such as hazard warning (possibly received from the cameras/sensors) or traffic information (based on the gps location).</li><li><strong>5. Smartphone interface</strong>: The smartphone interface enables app integration and vehicle status access. The owner´s smartphone, running the <strong>myAudi App</strong>, enables <strong>accessing calendar information</strong>, <strong>finding the car or navigation functionality</strong> and <strong>remote comfort features</strong>. This last features are done through the <strong>SmartPhoneConnectability</strong> component, which is able to send the signals to the <strong>HeatedSeatCU</strong>, <strong>CentralLockingCU</strong> and <strong>AuxiliaryHeatingCU</strong>.</li></ul><p><strong>6. Gateway Control Unit</strong>: The Gateway Control Unit connects <strong>in-vehicle networks</strong> with <strong>external networks</strong> such as the HERE or Google Servers, AudiCar 2 Backend and Online Speech Recognition Backend.</p><p><strong>7. HERE Servers</strong>: The model also represents the functionality provided by the <strong>HERE Servers</strong> as the <strong>HERETrafficLoadCalculation</strong>, <strong>HERERouteCalculation</strong> and <strong>HERELocationBasedSearch</strong> components.</p><p><strong>8. Google Navigation backend</strong>: The functionality provided by the <strong>google navigation backend</strong> is also shown in the model by the <strong>GoogleSearch</strong> and <strong>GoogleEarthNavigationBackend</strong> components.</p><h2 id="🏷️-label-description" tabindex="-1">🏷️ Label description <a class="header-anchor" href="#🏷️-label-description" aria-label="Permalink to &quot;🏷️ Label description&quot;">​</a></h2><ul><li><h3 id="🗂️-data-labels" tabindex="-1">🗂️ Data Labels: <a class="header-anchor" href="#🗂️-data-labels" aria-label="Permalink to &quot;🗂️ Data Labels:&quot;">​</a></h3><ul><li><h3 id="datatype" tabindex="-1">DataType: <a class="header-anchor" href="#datatype" aria-label="Permalink to &quot;DataType:&quot;">​</a></h3><ul><li><strong>VehicleIdentifier</strong>: The data is the identifier of the vehicle</li><li><strong>Car2X</strong>:</li><li><strong>GPSLocation</strong>: The data is the GPSLocation of the car</li><li><strong>Navigation</strong>: The data is the navigation data of the route</li><li><strong>ExternalAuth</strong>: The data is an external authentication</li><li><strong>Traffic</strong>: The data is the traffic data</li><li><strong>DriveControlInstruction</strong>: The data is a drive control instruction</li></ul></li><li><h3 id="granularity" tabindex="-1">Granularity: <a class="header-anchor" href="#granularity" aria-label="Permalink to &quot;Granularity:&quot;">​</a></h3><ul><li><strong>Detailed</strong>: The granularity of the data is detailed</li><li><strong>Aggregated</strong>: The granularity of the data is aggregated</li></ul></li><li><h3 id="status" tabindex="-1">Status: <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status:&quot;">​</a></h3><ul><li><strong>GatewayChecked</strong>: The status of the gateway is checked</li></ul></li></ul></li><li><h3 id="🏷️-node-labels" tabindex="-1">🏷️ Node Labels: <a class="header-anchor" href="#🏷️-node-labels" aria-label="Permalink to &quot;🏷️ Node Labels:&quot;">​</a></h3><ul><li><h3 id="trigger" tabindex="-1">Trigger: <a class="header-anchor" href="#trigger" aria-label="Permalink to &quot;Trigger:&quot;">​</a></h3><ul><li><strong>Automatic</strong>: This node is triggered automatically</li><li><strong>Manual</strong>: This node is a triggered manually</li></ul></li><li><h3 id="location" tabindex="-1">Location: <a class="header-anchor" href="#location" aria-label="Permalink to &quot;Location:&quot;">​</a></h3><ul><li><strong>Onboard</strong>: This node resides on board</li><li><strong>AudiCloud</strong>: This node resides in the Audi cloud</li><li><strong>Smartphone</strong>: This node resides in the smartphone</li><li><strong>HEREBackend</strong>: This node resides in the HERE backend</li><li><strong>GoogleBackend</strong>: This node resides in the Google backend</li></ul></li></ul></li></ul><h2 id="⚠️-constraints" tabindex="-1">⚠️ Constraints <a class="header-anchor" href="#⚠️-constraints" aria-label="Permalink to &quot;⚠️ Constraints&quot;">​</a></h2><ul><li>There are no constraints for this model</li></ul><h2 id="🚨-violations" tabindex="-1">🚨 Violations <a class="header-anchor" href="#🚨-violations" aria-label="Permalink to &quot;🚨 Violations&quot;">​</a></h2><ul><li><strong>None</strong></li></ul>',27))]))}});export{p as __pageData,f as default};
